class Solution:
    def canCompleteCircuit(self, gas: list[int], cost: list[int]) -> int:
        total_gas_difference = 0
        current_tank = 0
        start_node = 0
        n = len(gas)

        for i in range(n):
            diff = gas[i] - cost[i]
            total_gas_difference += diff
            current_tank += diff

            if current_tank < 0:
                current_tank = 0
                start_node = i + 1

        if total_gas_difference >= 0:
            return start_node
        else:
            return -1
